        from tempograph.builder import build_graph

        # core.py: a hub function called from 8+ files
        (tmp_path / "core.py").write_text(
            "def hub_function(x): return x\n"
            "def side_function(x): return x + 1\n"
        )
        # 8 files call hub_function
